var reorderedPowerOf2 = function(n) {
    const sig = s => s.split('').sort().join('');
    const target = sig(String(n));
    for (let e = 0; e < 31; e++) {
        if (sig(String(2 ** e)) === target) return true;
    }
    return false;
};
